spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var centerY = H / 2 + 10;
    var padding = 60;
    var maxVal = 10;
    var spacing = (W - padding * 2) / maxVal;

    function getX(val) {
      return padding + val * spacing;
    }

    // Draw Number Line axis
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(padding - 20, centerY);
    ctx.lineTo(W - padding + 20, centerY);
    ctx.stroke();

    // Draw ticks and labels
    for (var i = 0; i <= maxVal; i++) {
      var tx = getX(i);
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(tx, centerY - 8);
      ctx.lineTo(tx, centerY + 8);
      ctx.stroke();

      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText(i.toString(), tx, centerY + 25);
    }

    // Animation phases (cycle repeats every 8 seconds)
    var totalDuration = 8000;
    var progress = (t % totalDuration) / totalDuration;

    var phase1End = 0.35; // 0.0 to 0.35: First jump (0 -> 4)
    var phase2End = 0.70; // 0.35 to 0.70: Second jump (4 -> 7)
    var phase3End = 0.95; // 0.70 to 0.95: Show result and pulse

    // Jump 1: 0 to 4
    if (progress > 0) {
      var t1 = Math.min(progress / phase1End, 1.0);
      var val1 = 4 * t1;
      var startX = getX(0);
      var endX = getX(val1);

      // Draw arc
      ctx.strokeStyle = '#3B82F6';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(startX, centerY);
      for (var x = startX; x <= endX; x++) {
        var ratio = (x - startX) / (getX(4) - startX);
        var arcY = centerY - Math.sin(ratio * Math.PI) * 45;
        ctx.lineTo(x, arcY);
      }
      ctx.stroke();

      // Addend 1 Label
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('4', getX(2), centerY - 55);
    }

    // Jump 2: 4 to 7
    if (progress > phase1End) {
      var t2 = Math.min((progress - phase1End) / (phase2End - phase1End), 1.0);
      var val2 = 4 + 3 * t2;
      var startX2 = getX(4);
      var endX2 = getX(val2);

      ctx.strokeStyle = '#EC4899';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(startX2, centerY);
      for (var x = startX2; x <= endX2; x++) {
        var ratio2 = (x - startX2) / (getX(7) - startX2);
        var arcY2 = centerY - Math.sin(ratio2 * Math.PI) * 35;
        ctx.lineTo(x, arcY2);
      }
      ctx.stroke();

      // Addend 2 Label
      ctx.fillStyle = '#F472B6';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('+3', getX(5.5), centerY - 45);
    }

    // Pulse at target and draw final equation
    if (progress > phase2End) {
      var t3 = (progress - phase2End) / (phase3End - phase2End);
      var pulseRadius = 10 + Math.sin(t * 0.015) * 4;

      ctx.fillStyle = '#10B981';
      ctx.beginPath();
      ctx.arc(getX(7), centerY, pulseRadius, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 20px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('4 + 3 = 7', W / 2, centerY - 80);
    } else {
      // Active indicator dot at current head
      var currentVal = 0;
      if (progress <= phase1End) {
        currentVal = 4 * (progress / phase1End);
      } else {
        currentVal = 4 + 3 * Math.min((progress - phase1End) / (phase2End - phase1End), 1.0);
      }
      ctx.fillStyle = '#FBBF24';
      ctx.beginPath();
      ctx.arc(getX(currentVal), centerY, 8, 0, Math.PI * 2);
      ctx.fill();
    }
  }
};
